{
  "summary": "This paper proposes vote-k, an unsupervised graph-based selective annotation method designed to improve annotation efficiency for few-shot in-context learning with large language models. By selecting a small, diverse, and representative subset of examples for annotation, combined with similarity-based prompt retrieval, vote-k achieves strong performance across diverse NLP tasks and model sizes while reducing annotation costs compared to random selection and finetuning.",
  "strengths": [
    {
      "point": "Novel selective annotation method tailored for in-context learning",
      "evidence": "Vote-k jointly optimizes diversity and representativeness via a graph-based voting scheme, specifically designed to select examples that improve prompt retrieval and in-context learning performance."
    },
    {
      "point": "Extensive empirical evaluation across diverse NLP tasks and model scales",
      "evidence": "Experiments on 10 datasets covering classification, reasoning, dialogue, semantic parsing, and generation demonstrate consistent improvements with vote-k over baselines and random selection."
    },
    {
      "point": "Demonstrated annotation cost savings and improved stability",
      "evidence": "Vote-k achieves higher performance with fewer annotated examples (e.g., 18 vs. 100) and reduces variance due to unlabeled data sampling, highlighting robustness."
    },
    {
      "point": "Insightful comparison between in-context learning and finetuning",
      "evidence": "Selective annotation benefits in-context learning but not finetuning, with vote-k outperforming finetuning under limited annotation budgets by large margins."
    },
    {
      "point": "Practical framework separating selective annotation and prompt retrieval",
      "evidence": "The two-step approach explicitly considers annotation cost and retrieval strategies, providing actionable guidance for efficient annotation design."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to recent advanced active learning methods",
      "evidence": "The paper omits comparisons to state-of-the-art active learning strategies combining uncertainty and diversity, weakening claims of novelty."
    },
    {
      "point": "Insufficient methodological details and ablations",
      "evidence": "No detailed rationale or sensitivity analysis for the hyperparameter k; unclear confidence scoring procedure and language model used for scoring."
    },
    {
      "point": "Limited evaluation of finetuning baselines and statistical rigor",
      "evidence": "Finetuning baselines are evaluated under limited settings without exploring data augmentation or regularization; no statistical significance testing reported."
    },
    {
      "point": "Reproducibility concerns due to missing implementation details",
      "evidence": "No specification of Sentence-BERT model variant, embedding dimensionality, or code and hyperparameter release."
    },
    {
      "point": "Ambiguity in key concepts and explanation clarity",
      "evidence": "Definitions of diversity and representativeness are informal; vote score computation lacks concrete formulas or pseudocode, hindering understanding."
    },
    {
      "point": "Scalability and generalizability limitations not addressed",
      "evidence": "No discussion on computational cost or approximations for large unlabeled pools; applicability beyond NLP tasks remains unexplored."
    },
    {
      "point": "Limited analysis of domain shift and embedding dependence",
      "evidence": "No systematic study of different domain shifts or embedding alternatives to Sentence-BERT, leaving robustness questions open."
    },
    {
      "point": "Incomplete exploration of interaction between selective annotation and prompt retrieval",
      "evidence": "The impact of different retrieval strategies on selective annotation effectiveness is noted but not thoroughly analyzed or ablated."
    }
  ],
  "questions": [
    {
      "question": "How sensitive is vote-k to the choice of the hyperparameter k and how should it be selected in practice?",
      "motivation": "Understanding parameter sensitivity is crucial for applying the method robustly across tasks and datasets."
    },
    {
      "question": "Would incorporating recent active learning methods that combine uncertainty and diversity improve or complement vote-k?",
      "motivation": "Comparing to or integrating with state-of-the-art active learning could strengthen the novelty and performance claims."
    },
    {
      "question": "How does vote-k scale computationally with very large unlabeled datasets, and can approximate nearest neighbor methods be used?",
      "motivation": "Scalability is important for practical deployment in real-world large-scale annotation scenarios."
    },
    {
      "question": "Can vote-k be effectively applied beyond NLP tasks, such as vision or multi-modal domains?",
      "motivation": "Demonstrating generalizability would broaden the impact and applicability of the method."
    },
    {
      "question": "What is the impact of different embedding models on vote-k’s performance and robustness?",
      "motivation": "Dependency on Sentence-BERT embeddings may limit robustness; exploring alternatives could improve generality."
    },
    {
      "question": "How does the confidence scoring step integrate with the graph-based selection, and what language model is used?",
      "motivation": "Clarifying this step is important for reproducibility and understanding the method’s contribution."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
